 1	import React from 'react';
 2	
 3	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import useMigrationPercentage from '@kubevirt-utils/resources/vm/hooks/useMigrationPercentage';
 6	import { Timestamp } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Card,
 9	  CardBody,
10	  CardTitle,
11	  Progress,
12	  ProgressMeasureLocation,
13	  Stack,
14	  StackItem,
15	} from '@patternfly/react-core';
16	
17	import { getMigrationProgressVariant } from '../utils/utils';
18	
19	type MigrationProgressStatusProps = {
20	  vmi: V1VirtualMachineInstance;
21	};
22	
23	const MigrationProgressStatus: React.FC<MigrationProgressStatusProps> = ({ vmi }) => {
24	  const { t } = useKubevirtTranslation();
25	
26	  const { endTimestamp, isFailed, percentage } = useMigrationPercentage(vmi);
27	
28	  const progressStatus = getMigrationProgressVariant(percentage, isFailed);
29	
30	  return (
31	    <StackItem>
32	      <Card>
33	        <CardTitle>{t('LiveMigration progress')}</CardTitle>
34	        <CardBody>
35	          <Stack hasGutter>
36	            <StackItem>
37	              {endTimestamp && (
38	                <>
39	                  {t('Complete time:')}{' '}
40	                  <Timestamp
41	                    className="virtual-machine-metrics-tab__migration-completed-timestamp"
42	                    simple
43	                    timestamp={endTimestamp}
44	                  />
45	                </>
46	              )}
47	            </StackItem>
48	            <StackItem>
49	              <Progress
50	                measureLocation={ProgressMeasureLocation.top}
51	                value={percentage}
52	                variant={progressStatus}
53	              />
54	            </StackItem>
55	          </Stack>
56	        </CardBody>
57	      </Card>
58	    </StackItem>
59	  );
60	};
61	
62	export default MigrationProgressStatus;

